// ── Decode round-trips ────────────────────────────────────────────────────────

#[test]
fn agent_id_full_round_trips() {
    let original = AgentId {
        org_id: "acme-corp".into(),
        team_id: "platform".into(),
        agent_id: "did:key:z6Mkm5rByiqq5UNbvPFPfXtGJwdg2kD1T".into(),
    };
    let bytes = original.encode_to_vec();
    let decoded = AgentId::decode(bytes.as_slice()).expect("decode AgentId");
    assert_eq!(decoded, original);
}

#[test]
fn check_action_response_allow_round_trips() {
    let golden = load_golden_bin("check_action_response_allow");
    let decoded = CheckActionResponse::decode(golden.as_slice()).expect("decode CheckActionResponse");
    assert_eq!(decoded.decision, Decision::Allow as i32);
    assert_eq!(decoded.decision_latency_us, 312);
    assert!(decoded.redact.is_none());
}
